const raw = $input.first().json;
const body = (raw.body !== undefined) ? raw.body : raw;
if (!body.job_id) throw new Error('Payload missing: job_id');
if (!Array.isArray(body.clip_prompts) || body.clip_prompts.length !== 3) throw new Error('Payload must have clip_prompts array of 3');
return [{ json: {
  job_id: body.job_id,
  topic: body.topic,
  title: body.title,
  hashtags: body.hashtags,
  narration: body.narration,
  clip_prompts: body.clip_prompts,
  audio_path: body.audio_path,
  subs_path: body.subs_path,
  audio_duration: body.audio_duration,
  subtitle_chunks: body.subtitle_chunks,
  sheet_row: body.sheet_row || null,
  start_time: body.start_time || Date.now()
} }];

const { execSync } = require('child_process');
const fs = require('fs');

const data          = $input.first().json;
const jobId         = data.job_id;
const videoUrls     = data.video_urls;
const subtitleChunks = data.subtitle_chunks || [];
const audioDuration = data.audio_duration || 25;

const inputDir  = '/data/ffmpeg/input';
const outputDir = '/data/ffmpeg/output';
if (!fs.existsSync(inputDir))  fs.mkdirSync(inputDir,  { recursive: true });
if (!fs.existsSync(outputDir)) fs.mkdirSync(outputDir, { recursive: true });

function run(cmd, timeoutMs) {
  let out = '';
  try {
    out = execSync(cmd, { encoding: 'utf-8', timeout: timeoutMs || 120000 });
  } catch(err) {
    out = (err.stdout || err.stderr || err.message || '').toString();
  }
  return out;
}

// ── STEP 1: Download all clips ────────────────────────────────
for (let i = 0; i < videoUrls.length; i++) {
  const dest = '/ffmpeg/input/' + jobId + '_clip' + i + '.mp4';
  console.log('Downloading clip ' + (i+1) + '/' + videoUrls.length + '...');
  const out = run(
    'docker exec ffmpeg-runner curl -sL --max-time 90 -o "' + dest + '" "' + videoUrls[i] + '" && echo "DL_OK"'
  );
  if (!out.includes('DL_OK'))
    throw new Error('Clip ' + i + ' download failed: ' + out.slice(-300));
  console.log('Clip ' + (i+1) + ' downloaded');
}

// ── STEP 2: Re-encode each clip to 1080×1920 (9:16) ──────────
// This ensures all clips have identical codec/resolution before concat.
// 1080×1920 = full HD vertical (standard for YouTube Shorts)
for (let i = 0; i < videoUrls.length; i++) {
  const src  = '/ffmpeg/input/' + jobId + '_clip' + i + '.mp4';
  const norm = '/ffmpeg/input/' + jobId + '_clip' + i + '_norm.mp4';
  console.log('Normalizing clip ' + (i+1) + ' to 1080x1920...');
  const out = run(
    'docker exec ffmpeg-runner ffmpeg -y -i "' + src + '" ' +
    '-vf "scale=1080:1920:force_original_aspect_ratio=decrease,pad=1080:1920:(ow-iw)/2:(oh-ih)/2:black" ' +
    '-c:v libx264 -crf 20 -preset fast -an ' +
    '"' + norm + '" 2>&1 && echo "NORM_OK"',
    180000
  );
  if (!out.includes('NORM_OK'))
    throw new Error('Normalize clip ' + i + ' failed: ' + out.slice(-400));
}
console.log('All clips normalized to 1080x1920');

// ── STEP 3: Write concat list ─────────────────────────────────
const concatLines = videoUrls.map((_,i) =>
  "file '/ffmpeg/input/" + jobId + '_clip' + i + "_norm.mp4'"
).join('\n');
fs.writeFileSync('/data/ffmpeg/input/' + jobId + '_concat.txt', concatLines, 'utf-8');

const concatRaw = '/ffmpeg/input/' + jobId + '_concat_raw.mp4';
let out = run(
  'docker exec ffmpeg-runner ffmpeg -y -f concat -safe 0 ' +
  '-i "/ffmpeg/input/' + jobId + '_concat.txt" -c copy "' + concatRaw + '" 2>&1 && echo "CONCAT_OK"',
  300000
);
if (!out.includes('CONCAT_OK'))
  throw new Error('FFmpeg concat failed: ' + out.slice(-500));
console.log('Clips concatenated');

// ── STEP 4: Write SRT subtitle file ──────────────────────────
// Style: large white bold text, centered at bottom, black outline
// Perfect readability on mobile 9:16 screen
function toSrtTime(sec) {
  const h  = Math.floor(sec / 3600);
  const m  = Math.floor((sec % 3600) / 60);
  const s  = Math.floor(sec % 60);
  const ms = Math.round((sec % 1) * 1000);
  return String(h).padStart(2,'0') + ':' + String(m).padStart(2,'0') + ':' +
         String(s).padStart(2,'0') + ',' + String(ms).padStart(3,'0');
}

let srt = '';
for (let i = 0; i < subtitleChunks.length; i++) {
  const c = subtitleChunks[i];
  srt += (i + 1) + '\n';
  srt += toSrtTime(c.start) + ' --> ' + toSrtTime(c.end) + '\n';
  srt += c.text.toUpperCase() + '\n\n';   // uppercase for Shorts style
}
fs.writeFileSync('/data/ffmpeg/input/' + jobId + '.srt', srt, 'utf-8');
console.log('SRT written (' + subtitleChunks.length + ' subtitle blocks)');

// ── STEP 5: Final assembly ─────────────────────────────────────
// video  = concatenated normalized clips
// audio  = ElevenLabs narration (MP3)
// -vf    = burn subtitles with large mobile-friendly style
// -shortest = cut to audio length (so extra video is trimmed)
const srtPath   = '/ffmpeg/input/' + jobId + '.srt';
const audioPath = '/ffmpeg/input/' + jobId + '_narration.mp3';
const finalPath = '/ffmpeg/output/' + jobId + '_final.mp4';

// Subtitle style for mobile 9:16 vertical video:
//   FontSize=28   — large, readable on phone
//   Alignment=2   — bottom center
//   Bold=1        — bold text
//   PrimaryColour=&H00FFFFFF  — white text
//   OutlineColour=&H00000000  — black outline
//   Outline=3     — thick outline for contrast on any background
//   MarginV=80    — 80px from bottom (above safe zone)
const subStyle = "FontSize=28,Alignment=2,Bold=1,PrimaryColour=&H00FFFFFF,OutlineColour=&H00000000,Outline=3,MarginV=80";
const subFilter = "subtitles='" + srtPath + "':force_style='" + subStyle + "'";

out = run(
  'docker exec ffmpeg-runner ffmpeg -y ' +
  '-i "' + concatRaw + '" ' +
  '-i "' + audioPath + '" ' +
  '-vf "' + subFilter + '" ' +
  '-c:v libx264 -crf 20 -preset fast ' +
  '-c:a aac -b:a 128k ' +
  '-movflags +faststart ' +         // optimised for streaming/upload
  '-shortest ' +                     // trim video to audio length
  '"' + finalPath + '" 2>&1 && echo "FINAL_OK"',
  600000
);
if (!out.includes('FINAL_OK'))
  throw new Error('Final assembly failed: ' + out.slice(-800));
console.log('Final video assembled: ' + finalPath);

const n8nFinalPath = '/data/ffmpeg/output/' + jobId + '_final.mp4';
if (!fs.existsSync(n8nFinalPath))
  throw new Error('Output file not found: ' + n8nFinalPath);

return [{ json: {
  ...data,
  output_filename:  jobId + '_final.mp4',
  final_video_path: n8nFinalPath,
  clips_used:       videoUrls.length,
  audio_duration:   audioDuration
}}];

const fs = require('fs');
const item = $input.first().json;
const filePath = item.final_video_path;

if (!fs.existsSync(filePath)) {
  throw new Error('Final video not found at: ' + filePath);
}

const buffer = fs.readFileSync(filePath);

return [{
  json: item,
  binary: {
    data: {
      data: buffer.toString('base64'),
      mimeType: 'video/mp4',
      fileName: item.output_filename,
      fileExtension: 'mp4'
    }
  }
}];

const driveNode   = $('Upload Animation to Drive').first().json;
const assembleData = $('Assemble Video').first().json;
const extractData  = $('Extract Payload').first().json;
const fileId = driveNode.id;

const videoUrl       = 'https://drive.google.com/uc?export=download&id=' + fileId;
const renderTimeSec  = Math.round((Date.now() - assembleData.start_time) / 1000);

console.log('Stage 2 complete. Job: ' + assembleData.job_id + ', Drive file: ' + fileId + ', Time: ' + renderTimeSec + 's');

return [{ json: {
  job_id:             assembleData.job_id,
  topic:              assembleData.topic,
  title:              assembleData.title,
  video_url:          videoUrl,
  drive_file_id:      fileId,
  render_time_seconds: renderTimeSec,
  sheet_row:          extractData.sheet_row,
  status:             'stage2_complete'
} }];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const clipPrompts = data.clip_prompts;

if (!Array.isArray(clipPrompts) || clipPrompts.length === 0)
  throw new Error('No clip_prompts in payload');

// Determine how many clips we need based on audio duration
// Each clip = 10 seconds. We need ceil(audioDuration / 10) clips.
// Minimum 2, maximum clipPrompts.length (default 3).
const audioDuration = data.audio_duration || 25;
const clipsNeeded   = Math.min(clipPrompts.length, Math.max(2, Math.ceil(audioDuration / 10)));
console.log('Audio duration: ' + audioDuration.toFixed(1) + 's → generating ' + clipsNeeded + ' clips of 10s each');

function apiPost(body) {
  return new Promise((resolve, reject) => {
    const buf = Buffer.from(JSON.stringify(body));
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/bytedance/seedance-1-lite/text-to-video',
      method: 'POST',
      headers: {
        'Authorization': 'Bearer ' + apiKey,
        'Content-Type': 'application/json',
        'Content-Length': buf.length
      }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => {
        try { resolve(JSON.parse(Buffer.concat(chunks).toString())); }
        catch(e) { reject(new Error('Bad JSON from Wavespeed: ' + Buffer.concat(chunks).toString().slice(0,200))); }
      });
    });
    req.on('error', reject);
    req.write(buf);
    req.end();
  });
}

// Submit clips in parallel (faster than sequential)
const submitPromises = [];
for (let i = 0; i < clipsNeeded; i++) {
  console.log('Submitting clip ' + (i+1) + '/' + clipsNeeded + '...');
  console.log('  Prompt: ' + clipPrompts[i].slice(0, 100) + '...');
  submitPromises.push(
    apiPost({
      prompt:          clipPrompts[i],
      aspect_ratio:    '9:16',       // vertical mobile format
      duration:        10,            // 10s per clip (Seedance max)
      resolution:      '720p',
      generate_audio:  false,         // we use ElevenLabs audio instead
      seed:            -1
    })
  );
}

const results = await Promise.all(submitPromises);

const task_ids = [];
for (let i = 0; i < results.length; i++) {
  const r = results[i];
  if (!r.data || !r.data.id)
    throw new Error('Wavespeed submit failed clip ' + i + ': ' + JSON.stringify(r));
  task_ids.push(r.data.id);
  console.log('Clip ' + (i+1) + ' submitted — task id: ' + r.data.id);
}

console.log('All ' + clipsNeeded + ' clips submitted in parallel. Waiting for generation...');

return [{ json: {
  ...data,
  task_ids,
  clips_count:  clipsNeeded,
  video_urls:   new Array(clipsNeeded).fill(null),
  poll_attempt: 0,
  all_done:     false
}}];

const https = require('https');
const data = $input.first().json;
const apiKey = $env.WAVESPEED_API_KEY;
const task_ids   = data.task_ids;
const video_urls = [...(data.video_urls || [null, null, null])];
const attempt    = (data.poll_attempt || 0) + 1;

console.log('--- Poll attempt #' + attempt + ' ---');

function apiGet(taskId) {
  return new Promise((resolve, reject) => {
    const req = https.request({
      hostname: 'api.wavespeed.ai',
      path: '/api/v3/predictions/' + taskId,
      method: 'GET',
      headers: { 'Authorization': 'Bearer ' + apiKey }
    }, (res) => {
      const chunks = [];
      res.on('data', c => chunks.push(c));
      res.on('end', () => resolve(JSON.parse(Buffer.concat(chunks).toString())));
    });
    req.on('error', reject);
    req.end();
  });
}

// Check each clip that is not yet complete
for (let i = 0; i < task_ids.length; i++) {
  if (video_urls[i] !== null) {
    console.log('Clip ' + i + ' already done, skipping');
    continue;
  }

  const r = await apiGet(task_ids[i]);
  const status = (r.data && r.data.status) || 'unknown';
  console.log('Clip ' + i + ' [' + task_ids[i] + '] status: ' + status);

  if (status === 'completed') {
    const url = r.data.outputs && r.data.outputs[0];
    if (!url) throw new Error('Clip ' + i + ' completed but output URL missing');
    video_urls[i] = url;
    console.log('Clip ' + i + ' ready: ' + url);
  } else if (status === 'failed') {
    throw new Error('Clip ' + i + ' FAILED: ' + JSON.stringify(r.data));
  } else {
    console.log('Clip ' + i + ' still ' + status + ' — will retry in 20s');
  }
}

const all_done = video_urls.every(u => u !== null);
const pending  = video_urls.filter(u => u === null).length;

if (all_done) {
  console.log('All 3 clips are ready! Proceeding to assembly.');
} else {
  console.log(pending + ' clip(s) still generating. Waiting 20s before next poll.');
}

return [{ json: {
  ...data,
  task_ids,
  video_urls,
  poll_attempt: attempt,
  all_done
}}];
